def bfs(graph, start):
    seen = {start}
    queue = [start]
    order = []

    while queue:
        curr = queue.pop(0)
        order.append(curr)

        for neighbor in graph.get(curr, []):
            if neighbor not in seen:
                seen.add(neighbor)
                queue.append(neighbor)

    return order

