def dijkstra(graph, start):
    dist = {v: float('inf') for v in graph}
    dist[start] = 0
    visited = set()
    nodes = list(graph.keys())

    while len(visited) < len(nodes):
        curr = None
        min_d = float('inf')
        for n in nodes:
            if n not in visited and dist[n] < min_d:
                min_d = dist[n]
                curr = n

        if curr is None:
            break

        visited.add(curr)
        for v, weight in graph[curr]:
            new_dist = dist[curr] + weight
            if new_dist < dist[v]:
                dist[v] = new_dist

    return dist

